const V20_KEYS={selected:'sfl_v20_selected_team',commissioner:'sfl_v20_commissioner',draft:'sfl_v20_draft_order',teamState:'sfl_v20_team_state',schema:'sfl_v20_schema'};
let v20SelectedTeam=localStorage.getItem(V20_KEYS.selected)||'los-angeles-avengers',v20Commissioner=localStorage.getItem(V20_KEYS.commissioner)==='1';
const v20OriginalAvengersRoster=typeof roster!=='undefined'?[...roster]:[],v20OriginalAvengersFA=typeof freeAgents!=='undefined'?[...freeAgents]:[];
let v20TeamState=JSON.parse(localStorage.getItem(V20_KEYS.teamState)||'{}');
function v20Rec(id){return V20_IMPORTED_TEAMS[id]||V20_IMPORTED_TEAMS['los-angeles-avengers']}function v20State(id){if(!v20TeamState[id])v20TeamState[id]={transactions:[],releaseLedger:[],starters:{},depth:{},draftPhilosophy:v20Rec(id).draftPhilosophy||'Not Set',roster:null};return v20TeamState[id]}
function v20Save(){localStorage.setItem(V20_KEYS.teamState,JSON.stringify(v20TeamState));localStorage.setItem(V20_KEYS.selected,v20SelectedTeam);localStorage.setItem(V20_KEYS.schema,'2')}
function v20Convert(p){return {...p,entry:p.college||'',years:Number(((String(p.terms||'').match(/(\d+)\s*yrs?/i)||[])[1])||1),stats:{},photo:'',age:'Pending'}}
function v20SharedFA(){return V20_SHARED_FREE_AGENTS.map(f=>v20Convert({...f,college:f.college||('Previous: '+(f.previousTeams||[]).join(', ')),terms:f.terms||'Unsigned',cap:f.cap||'$0'}))}
function v20PersistCurrent(){const s=v20State(v20SelectedTeam);if(v20SelectedTeam!=='los-angeles-avengers')s.roster=roster;s.transactions=transactionHistory||[];s.releaseLedger=releaseLedger||[];s.starters=starters||{};s.depth=depth||{};v20Save()}
function v20ApplyTeam(id){if(typeof roster!=='undefined')v20PersistCurrent();v20SelectedTeam=id;const t=v20Rec(id),s=v20State(id);document.documentElement.dataset.team=id;document.querySelector('header h1').textContent='SFL COMMAND CENTER v2.3';document.querySelector('header .eyebrow').textContent=t.name.toUpperCase();document.querySelector('header .sub').textContent=t.name+' Front Office · League Command Center';if(id==='los-angeles-avengers'){roster=[...v20OriginalAvengersRoster];freeAgents=[...v20OriginalAvengersFA,...v20SharedFA()];}else{roster=(s.roster||t.players||[]).map(v20Convert);freeAgents=v20SharedFA();}starters=s.starters||{};depth=s.depth||{};releaseLedger=s.releaseLedger||[];transactionHistory=s.transactions||[];latestTransaction=transactionHistory[0]?.description||'None yet';openPlayer=null;openFreeAgent=null;try{refreshPersonnelFilters();renderRoster();renderFreeAgents();renderDepth();updateRosterMetrics();renderCapSheet();renderDashboard();renderStats();}catch(e){console.error('v20 render',e)}v20Identity();v20DraftSummary();v20IsolateStats();v20Save()}
function v20Identity(){let box=document.getElementById('v20TeamIdentity');if(!box){box=document.createElement('div');box.id='v20TeamIdentity';box.className='card teamIdentity';document.getElementById('team')?.prepend(box)}const t=v20Rec(v20SelectedTeam),s=t.staff||{},m=t.media||{};box.innerHTML=`<h2>${t.name}</h2><div class="small">${s.Owner||'Owner: Not supplied'} · ${s['Head Coach']||'Head Coach: Vacant'}</div><div class="small">${m.Location||m.City||''} ${s['Home Field']?'· '+s['Home Field']:''}</div><div class="leagueAudit">Active players: ${roster.length} · Submitted roster: ${t.submittedRoster??'—'} · FA overrides: ${t.overrideCount||0} · Submitted salary: ${t.submittedSalary||'—'}</div><div class="philosophyBox"><b>Draft Philosophy</b><textarea id="v20Philosophy">${v20State(v20SelectedTeam).draftPhilosophy||'Not Set'}</textarea><button id="v20SavePhilosophy">Save Philosophy</button></div>`;document.getElementById('v20SavePhilosophy').onclick=()=>{v20State(v20SelectedTeam).draftPhilosophy=document.getElementById('v20Philosophy').value;v20Save()}}
function v20IsolateStats(){const stats=document.getElementById('stats');if(!stats)return;if(v20SelectedTeam==='los-angeles-avengers'){stats.querySelector('.isolationNotice')?.remove();stats.querySelectorAll(':scope > *').forEach(x=>x.style.display='')}else{stats.querySelectorAll(':scope > *').forEach(x=>x.style.display='none');let n=stats.querySelector('.isolationNotice');if(!n){n=document.createElement('div');n.className='card isolationNotice';stats.appendChild(n)}n.style.display='block';n.textContent='No team statistics have been supplied for '+v20Rec(v20SelectedTeam).name+'. Los Angeles statistics are intentionally isolated.'}}
function v20DefaultDraft(){let overall=1,out=[];for(let r=1;r<=6;r++)for(let slot=1;slot<=V20_TEAM_ORDER.length;slot++)out.push({id:`R${r}P${slot}`,round:r,slot,overall:overall++,teamId:V20_TEAM_ORDER[slot-1],originalTeamId:V20_TEAM_ORDER[slot-1],complete:false,selectedPlayer:null,type:'STANDARD'});return out}let v20Draft=JSON.parse(localStorage.getItem(V20_KEYS.draft)||'null')||v20DefaultDraft();function v20SaveDraft(){localStorage.setItem(V20_KEYS.draft,JSON.stringify(v20Draft));v20DraftEditor();v20DraftSummary()}function v20Opts(sel){return V20_TEAM_ORDER.map(id=>`<option value="${id}" ${id===sel?'selected':''}>${v20Rec(id).name}</option>`).join('')}
function v20DraftSummary(){const el=document.getElementById('pickList');if(!el)return;const picks=v20Draft.filter(p=>p.teamId===v20SelectedTeam&&!p.complete).slice(0,12);el.innerHTML=picks.length?picks.map(p=>`<div class="pick"><span>${p.type==='COMP'?'Compensatory':'Round '+p.round}, Pick ${p.slot}</span><b>#${p.overall}</b></div>`).join(''):'<div class="small">No current selections assigned.</div>'}
function v20CommissionerPanel(){let sec=document.getElementById('v20CommissionerPanel');if(sec)return;sec=document.createElement('section');sec.id='v20CommissionerPanel';sec.className='view commissionerOnly';sec.innerHTML='<div class="card"><div class="title">Commissioner Draft Order Editor</div><div class="small">Shared league pick ownership. Changes update every team dashboard.</div><button id="addCompPick">Add Compensatory Pick</button></div><div id="v20DraftEditor" class="draftEditorGrid" style="margin-top:14px"></div>';document.querySelector('main').append(sec);const btn=document.createElement('button');btn.className='tab commissionerOnly';btn.textContent='Commissioner';document.querySelector('nav').append(btn);btn.onclick=()=>{document.querySelectorAll('.tab,.view').forEach(x=>x.classList.remove('active'));btn.classList.add('active');sec.classList.add('active');v20DraftEditor()};document.getElementById('addCompPick').onclick=()=>{const max=Math.max(...v20Draft.map(p=>p.overall),0);v20Draft.push({id:'COMP-'+Date.now(),round:'COMP',slot:v20Draft.filter(p=>p.type==='COMP').length+1,overall:max+1,teamId:v20SelectedTeam,originalTeamId:v20SelectedTeam,complete:false,selectedPlayer:null,type:'COMP',reason:'Commissioner award'});v20SaveDraft()}}
function v20DraftEditor(){const el=document.getElementById('v20DraftEditor');if(!el)return;el.innerHTML=v20Draft.map(p=>`<div class="draftPickBox ${p.complete?'complete':''}"><b>#${p.overall} · ${p.type==='COMP'?'COMP':'R'+p.round+' P'+p.slot}</b><div class="small">Original: ${v20Rec(p.originalTeamId).name}</div><select data-pick="${p.id}">${v20Opts(p.teamId)}</select><input data-player="${p.id}" placeholder="Selected player" value="${p.selectedPlayer||''}"><label class="small"><input type="checkbox" data-complete="${p.id}" ${p.complete?'checked':''}> Complete</label></div>`).join('');el.querySelectorAll('[data-pick]').forEach(x=>x.onchange=()=>{v20Draft.find(p=>p.id===x.dataset.pick).teamId=x.value;v20SaveDraft()});el.querySelectorAll('[data-player]').forEach(x=>x.onchange=()=>{v20Draft.find(p=>p.id===x.dataset.player).selectedPlayer=x.value||null;v20SaveDraft()});el.querySelectorAll('[data-complete]').forEach(x=>x.onchange=()=>{v20Draft.find(p=>p.id===x.dataset.complete).complete=x.checked;v20SaveDraft()})}
function v20PaintCommissioner(){document.body.classList.toggle('commissionerMode',v20Commissioner);const b=document.getElementById('commissionerToggle');b.classList.toggle('on',v20Commissioner);b.textContent='Commissioner Mode: '+(v20Commissioner?'On':'Off')}function v20Init(){const sel=document.getElementById('leagueTeamSelector');sel.innerHTML=V20_TEAM_ORDER.map(id=>`<option value="${id}">${v20Rec(id).name}</option>`).join('');sel.value=v20SelectedTeam;sel.onchange=()=>v20ApplyTeam(sel.value);document.getElementById('commissionerToggle').onclick=()=>{v20Commissioner=!v20Commissioner;localStorage.setItem(V20_KEYS.commissioner,v20Commissioner?'1':'0');v20PaintCommissioner()};v20CommissionerPanel();v20PaintCommissioner();v20ApplyTeam(v20SelectedTeam);v20DraftEditor()}window.addEventListener('load',v20Init);window.addEventListener('beforeunload',v20PersistCurrent);
